function TeslaStatus() {
  const [battery, setBattery] = React.useState(78);
  const [climateOn, setClimateOn] = React.useState(false);
  const [locked, setLocked] = React.useState(true);
  const range = Math.round(battery * 3.2);

  return (
    <div style={{padding:20,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',background:'#0a0a0a',color:'#fff',borderRadius:12}}>
      <div style={{fontSize:20,fontWeight:700,marginBottom:16,textAlign:'center'}}>Model 3</div>
      <div style={{display:'flex',justifyContent:'center',marginBottom:20}}>
        <div style={{width:120,height:120,borderRadius:'50%',border:'8px solid #34C759',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center'}}>
          <div style={{fontSize:32,fontWeight:700}}>{battery}%</div>
          <div style={{fontSize:12,color:'#888'}}>{range} mi</div>
        </div>
      </div>
      <div style={{display:'flex',justifyContent:'space-around',marginBottom:20}}>
        <button onClick={()=>setClimateOn(!climateOn)}
          style={{padding:'10px 16px',borderRadius:10,border:'none',background:climateOn?'#007AFF':'#333',color:'#fff',cursor:'pointer',fontSize:13}}>
          {climateOn?'❄️ AC On':'🌡️ AC Off'}
        </button>
        <button onClick={()=>setLocked(!locked)}
          style={{padding:'10px 16px',borderRadius:10,border:'none',background:locked?'#34C759':'#FF3B30',color:'#fff',cursor:'pointer',fontSize:13}}>
          {locked?'🔒 Locked':'🔓 Unlocked'}
        </button>
      </div>
      <div style={{display:'flex',gap:8,marginTop:'auto'}}>
        <button onClick={()=>setBattery(Math.min(100,battery+5))}
          style={{flex:1,padding:10,borderRadius:8,border:'1px solid #333',background:'#1a1a1a',color:'#fff',cursor:'pointer'}}>
          +Charge
        </button>
        <button onClick={()=>setBattery(Math.max(0,battery-5))}
          style={{flex:1,padding:10,borderRadius:8,border:'1px solid #333',background:'#1a1a1a',color:'#fff',cursor:'pointer'}}>
          -Drive
        </button>
      </div>
    </div>
  );
}
render(<TeslaStatus/>);
